import{_ as b,o as e,c as a,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"波克比","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/波克比.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/波克比.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/7.系列随从/宝可梦系列/1.宝可梦/波克比.md"};function o(d,r,l,_,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"波克比",tabindex:"-1"},[t("波克比 "),p("a",{class:"header-anchor",href:"#波克比","aria-label":'Permalink to "波克比"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"汹涌疾风021")])])],-1),n('<h1 id="波克比-1" tabindex="-1">波克比 <a class="header-anchor" href="#波克比-1" aria-label="Permalink to &quot;波克比&quot;">​</a></h1><p>【波克比】</p><p>D+500<br> 独立随从</p><p>波克比，针球宝可梦，壳内好像塞满了很多幸福，据说如果能温柔对待它，它就会把幸运分给对方。</p><p>系别：妖精系<br> ▓▓▓▓属性<br> ▓▓生理属性<br> ■力量2<br> ■敏捷4<br> ■耐力6<br> ▓▓心智属性<br> ■智力2<br> ■感知6<br> ■决心4<br> ▓▓互动属性<br> ■风度4<br> ■操控2<br> ■沉着2</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动3-反射3<br> ■求生3-强韧3-动物沟通3<br> ■射击1<br> ■武技3-拳3</p><p>▓▓心智系<br> ■学识5-魔法5<br> ■器用1<br> ■手艺1<br> ■专注5-意志5</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达3-肢体语言3<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 1<br> ▓速度 7米<br> ▓先攻 6<br> ▓防御 5+1<br> ▓生命值 12<br> ▓意志力池 6<br> ▓意志 14+2/15+2（选择了超幸运特性）<br> ▓反射 10+1/11+2（选择了超幸运特性）<br> ▓强韧 12+2/13+2（选择了超幸运特性）<br> ▓侦查 7+1/8+1（选择了超幸运特性）<br> ▓敏感范围 140米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的每1点附加成功会在回合开始时额外提供1点基础Ap并提高3米额外移速<br> 耐力上的每1点附加成功会为其提供5点生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升或者获得1点全检定上的机运加值，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：<br> 普通攻击预设：力量+武技+拳+天生武器伤害=8+1（选择了天恩特性）/5+4（选择了活力特性）/9+1（选择了超幸运特性）</p><p>宝可梦技艺近战攻击预设：力量+武技+拳+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御5+1 针对龙类生物攻击获得2全伤害吸收</p><p>▓▓▓▓性别：公/母（购买时选定其中一种，选定之后无法更改）</p><p>▓▓▓▓特性：<br> 【妖精系宝可梦】：波克比在面对龙类生物（认定为龙/有龙系血统的生物/使用龙系魔法攻击波克比）时，获得针对该类生物攻击的2点全伤害吸收。当波克比受到毒素异常点数时，毒素异常点数的负面效果翻倍计算。因此特性额外丢失的生命值会在移除所有毒素异常点数时一并恢复。</p><p>【幸运化身】：提到波克比，所有的训练家都会想要拥有一只。因为波克比的象征意义绝不仅仅是只稀有的宝可梦而已，它更象征着运气加身。拥有波克比的训练家获得1点全检定的机运加值。</p><p>【天恩】：波克比是受上天眷顾的幸运宝可梦，当选择了天恩特性的波克比使用带有攻击命中后造成的异常点数类型的宝可梦技能时，若附加的异常点数为可豁免的，可使可豁免异常点数中三分之一的异常点数转化为不可豁免的同名异常点数，至多转化3点。若一次攻击中附带了多个类型的异常点数，则转化的异常点数共用转化上限。</p><p>【活力】：波克比总是充满活力，这样的特性或许让波克比在细微之处粗枝大叶，却也让它做什么事都能一往无前。选择了活力特性的波克比在进行攻击检定时，减少3点攻击检定DP，并且获得3点来自于祝福的附加成功。</p><p>【超幸运】：波克比是宝可梦中幸运的代表，拥有波克比的训练家无一不是上天的宠儿。选择了超幸运特性的波克比和训练家额外获得1点全检定的机运加值。</p><p>以上三种特性必须在购买时选定其中一种，一旦选定不可更改。<br> ▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>飞行系技能：空气之刃 神鸟猛击 燕返 双翼 啄 羽栖 飞翔</p><p>一般系技能：神速 三重攻击 祈愿 巨声 拍击 舍身冲撞 泰山压顶 替身 再来一次 百万吨重拳 守住 治愈铃声 破坏光线 硬撑 高速星星 生蛋</p><p>超能系技能：神通力 瞬间失忆 精神冲击 预知未来 意念头锤 冥想 光墙 反射壁 睡觉 精神强念</p><p>格斗系技能：波导弹 吸取拳</p><p>火系技能：喷射火焰 大字爆炎 热风</p><p>电系技能：电磁波</p><p>草系技能：打草结 日光束 魔法叶</p><p>水系技能：求雨 生命水滴</p><p>幽灵系技能：暗影球</p><p>妖精系技能：撒娇 天使之吻 妖精之风 吸取之吻 嬉闹 魔法闪耀</p><p>恶系技能：诡计 投掷</p><p>钢系技能：修长之角</p><p>岩石系技能：原始之力</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>DP转换说明：</p><p>【波克基古】<br> 由波克比支付10xp进化而来，波克比进化必须要亲密度达到120以上<br> 独立随从<br> 波克基古视为C级召唤物<br> 波克基古仅能由波克比进化而来，不可单独购买</p><p>波克基古，幸福宝可梦，波克比的进化形，据说它是为了将幸福带给性格温柔的人而现身的。</p><p>系别：妖精+飞行系<br> ▓▓▓▓属性<br> ▓▓生理属性<br> ■力量6<br> ■敏捷9<br> ■耐力11<br> ▓▓心智属性<br> ■智力6<br> ■感知11<br> ■决心9<br> ▓▓互动属性<br> ■风度9<br> ■操控6<br> ■沉着6</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动5-反射5<br> ■求生5-强韧5-动物沟通5<br> ■射击1<br> ■武技5-拳5</p><p>▓▓心智系<br> ■学识8-魔法8<br> ■器用1<br> ■手艺1<br> ■专注8-意志8</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达5-肢体语言5<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 3<br> ▓速度 21米<br> ▓先攻 15<br> ▓防御 10+2<br> ▓生命值 24<br> ▓意志力池 17<br> ▓意志 25+4/27+4（选择了超幸运特性）<br> ▓反射 19+3/21+3（选择了超幸运特性）<br> ▓强韧 21+4/23+4（选择了超幸运特性）<br> ▓侦查 12+2/14+2（选择了超幸运特性）<br> ▓敏感范围 260米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的每1点附加成功会在回合开始时额外提供1点基础Ap并提高3米额外移速<br> 耐力上的每1点附加成功会为其提供5点生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升或者获得1点全检定上的机运加值，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰</p><p>▓▓▓▓攻击预设：<br> 普通攻击预设：力量+武技+拳+天生武器伤害+风度全检定1=20+3（选择了天恩特性）/14+9（选择了活力特性）/22+3（选择了超幸运特性）</p><p>宝可梦技艺近战攻击预设：力量+武技+拳+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御10+2 针对龙类生物的攻击获得3全伤害吸收</p><p>▓▓▓▓性别：公/母（购买时选定其中一种，选定之后无法更改）</p><p>▓▓▓▓特性：<br> 【提升：妖精系宝可梦】：波克基古的妖精力量逐渐从体内涌出，尤其是其中对龙类力量的排斥力格外突出。波克基古针对龙类生物的攻击获得的全伤害吸收提升至3。</p><p>【飞行系宝可梦】：进化后的波克基古长出了娇小的翅膀，波克基古获得了机动性普通的飞行能力。</p><p>【提升：天恩】：当波克基古使用带有攻击命中后造成的异常点数类型的宝可梦技能时，若附加的异常点数为可豁免的，可使可豁免异常点数中三分之一的异常点数转化为不可豁免的同名异常点数，至多转化4点。若一次攻击中附带了多个类型的异常点数，则转化的异常点数共用转化上限。</p><p>【提升：活力】：当波克基古使用攻击检定时，其攻击检定减少DP提升至6，获得的附加成功提升至6。</p><p>【提升：超幸运】：选择了超幸运特性的波克基古和它的训练家，全检定获得的机运加值提升至2。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>同【波克比】</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><p>【波克基斯】<br> 由波克基古使用光之石进化而来，波克基古进化必须要亲密度达到220以上<br> 独立随从<br> 波克基斯视为B级召唤物<br> 波克基斯仅能由波克基古进化而来，不可单独购买</p><p>波克基斯，祝福宝可梦，波克基古的进化形，绝对不会出现在发生纷争的地方，近来很难见到它的身影了。</p><p>系别：妖精+飞行系<br> ▓▓▓▓属性<br> ▓▓生理属性<br> ■力量11<br> ■敏捷14<br> ■耐力16<br> ▓▓心智属性<br> ■智力11<br> ■感知16<br> ■决心14<br> ▓▓互动属性<br> ■风度14<br> ■操控11<br> ■沉着11</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动8-反射8<br> ■求生8-强韧8-动物沟通8<br> ■射击1<br> ■武技8-拳8</p><p>▓▓心智系<br> ■学识11-魔法11<br> ■器用1<br> ■手艺1<br> ■专注11-意志11</p><p>▓▓互动系<br> ■洞察1<br> ■隐秘1<br> ■表达8-肢体语言8<br> ■社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 5<br> ▓速度 36米<br> ▓先攻 25<br> ▓防御 15+3<br> ▓生命值 36<br> ▓意志力池 29<br> ▓意志 38+6/41+6（选择了超幸运特性）<br> ▓反射 32+5/35+5（选择了超幸运特性）<br> ▓强韧 34+6/37+6（选择了超幸运特性）<br> ▓侦查 19+3/22+3（选择了超幸运特性）<br> ▓敏感范围 380米</p><p>▓▓▓▓关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的3DP增强加值，可携带物品体积额外提升4点<br> 敏捷上的每1点附加成功会在回合开始时额外提供1点基础Ap并提高3米额外移速<br> 耐力上的每1点附加成功会为其提供5点生命值</p><p>智力上的每1点附加成功会为其提供每天一次，重投某个骰子的能力，但无论其结果如何，都必须接受那个骰子的结果<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升或者获得1点全检定上的机运加值，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰<br> ▓▓▓▓攻击预设：<br> 普通攻击预设：力量+武技+拳+天生武器伤害+2风度全检定加值+6力量附加成功加值=35+5（选择了天恩特性）/25+15（选择了活力特性）/38+5（选择了超幸运特性）</p><p>宝可梦技艺近战攻击预设：力量/敏捷+武技+拳+天生武器伤害+训练家专业：指挥+技能效果。</p><p>宝可梦技艺投掷攻击预设：力量/敏捷+运动+投掷+训练家专业：指挥+技能效果。</p><p>宝可梦技艺施法攻击预设：智力/感知+学识+魔法+训练家专业：指挥+技能效果。</p><p>以上三种攻击预设只在宝可梦学习了具有该预设模式的技艺后方可使用。</p><p>▓▓▓▓防御预设：基础防御15+3 具有针对龙类生物全伤害吸收4</p><p>▓▓▓▓性别：公/母（购买时选定其中一种，选定之后无法更改）</p><p>▓▓▓▓特性：</p><p>【提升：妖精系宝可梦】：波克基斯就是龙之克星，现在波克基斯对龙类生物的伤害吸收提升至4。</p><p>【提升：飞行系宝可梦】：波克基斯的飞行机动性提升至良好。</p><p>【提升：天恩】：当波克基斯使用带有攻击命中后造成的异常点数类型的宝可梦技能时，若附加的异常点数为可豁免的，可使可豁免异常点数中三分之一的异常点数转化为不可豁免的同名异常点数，至多转化6点。若一次攻击中附带了多个类型的异常点数，则转化的异常点数共用转化上限。</p><p>【提升：活力】：当波克基斯使用攻击检定时，其攻击检定减少DP提升至10，获得的附加成功提升至10。</p><p>【提升：超幸运】：选择了超幸运特性的波克基古和它的训练家，全检定获得的机运加值提升至3。</p><p>▓▓▓▓装备位：</p><p>▓▓▓▓亲密度： /250</p><p>▓▓▓▓可学习技能：</p><p>同【波克比】。</p><p>▓▓▓▓已学习技能：</p><p>▓▓▓▓购买记录：</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',101)])])}const P=b(s,[["render",o]]);export{f as __pageData,P as default};
